// ===== PERMISO DE EXPORTACIÓN (Interlog / IFManager) — solo EXPORTACIÓN (E) =====
{
  const subjPE = String($json.emailSubject ?? $json.subject ?? '');
  const isIFManagerDest = /Destinaci[oó]n\s+SIM\s*:/i.test(subjPE) && /Referencia\s*:/i.test(subjPE);
  if (isIFManagerDest) {
    const mPermiso = subjPE.match(/Destinaci[oó]n\s+SIM\s*:\s*([A-Za-z0-9]+)/i);
    const permiso = mPermiso ? mPermiso[1].trim() : null;
    const mTipo = permiso ? permiso.match(/([A-Za-z])C/i) : null;   // letra antes de la C: E=export, I=import
    const tipoLetra = mTipo ? mTipo[1].toUpperCase() : '';

    if (tipoLetra !== 'E') {
      // Importación u otra destinación no-export → ignorar, no se guarda en ninguna carpeta
      return { json: { tipo: 'destinacion_ignorar', permisoNumber: permiso, tipoLetra }, binary: $binary };
    }

    let ordenPE = null;
    const mRef = subjPE.match(/Referencia\s*:\s*([0-9,\s]+)/i);
    if (mRef) {
      const refs = mRef[1].split(',').map(s => s.trim()).filter(Boolean);
      ordenPE = refs[1] || null;
    }
    const ordenSlot = ordenPE || 'orden';
    return {
      json: {
        tipo: 'permiso_exportacion',
        orderNumber: ordenPE,
        newFileName: `${permiso}_${ordenSlot}_PE.pdf`,
        incompleto: !ordenPE || !permiso,
        permisoNumber: permiso,
        tipoLetra,
        shipmentNumber: null,
        shippingPointNormalized: '',
        hasExportPermit: false,
        emailSubject: subjPE
      },
      binary: $binary
    };
  }
}
// ===== fin guard PE =====

/**
 * Nodo: "Clasificar Documento y renombrar pdf"
 * Tarea...detectar Permiso de Exportación en FACTURAS y extraer Shipping
 */

const raw  = ($json.text || '');
const norm = raw.normalize('NFD').replace(/[\u0300-\u036f]/g, '');

/* ======= Asunto del email (desde el item, no desde $items()) ======= */
const emailSubject = $json.emailSubject ?? $json.subject ?? $json.headers?.subject ?? null;
let subjectCode = $json.subjectCode ?? (emailSubject ? String(emailSubject).trim().slice(0, 4) : null);
subjectCode = subjectCode ? String(subjectCode).trim().slice(0, 4).toUpperCase() : null;

const stripZeros = (s) => {
  const x = String(s || '').replace(/^0+/, '');
  return x === '' ? '0' : x;
};
const pick = (...vals) => vals.find(v => v != null && v !== '') ?? null;

const normalizeNamePart = (s) => String(s || '')
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^\w.\-]+/g, '_')
  .replace(/_{2,}/g, '_')
  .replace(/^_+|_+$/g, '')
  .toUpperCase();

const pickAllNumeric = (s, minLen = 6) => {
  if (!s) return [];
  return [...s.matchAll(new RegExp(String.raw`\b0*([0-9]{${minLen},})\b`, 'g'))]
         .map(m => stripZeros(m[1]));
};

const firstLineMatch = (re) => {
  const m = raw.match(new RegExp(`^.*${re.source}.*$`, 'im'));
  return m ? m[0] : null;
};

const extractOrderFromInternalDoc = (text) => {
  const lines = text.split(/\r?\n/);
  const chosen = [];
  const label = /(?:Internal\s+Document\s+Number|Internal\s+Order\s+Number|N[úu]mero\s+de\s+Orden\s+Intern[ao])/i;
  const firstLongNum = (s) => {
    const arr = pickAllNumeric(s, 6);
    return arr.length ? arr[0] : null;
  };
  for (let i = 0; i < lines.length; i++) {
    const m1 = lines[i].match(new RegExp(label.source + String.raw`\s*[:#-]?\s*([^\n]*)`, 'i'));
    if (m1) {
      let n1 = firstLongNum(m1[1]);
      if (!n1 && lines[i + 1] && !new RegExp(label.source, 'i').test(lines[i + 1])) {
        n1 = firstLongNum(lines[i + 1]);
      }
      const next = lines[i + 1];
      const m2 = next ? next.match(new RegExp(label.source + String.raw`\s*[:#-]?\s*([^\n]*)`, 'i')) : null;
      if (m2) {
        let n2 = firstLongNum(m2[1]);
        if (!n2 && lines[i + 2] && !new RegExp(label.source, 'i').test(lines[i + 2])) {
          n2 = firstLongNum(lines[i + 2]);
        }
        if (n2) chosen.push(n2);
        else if (n1) chosen.push(n1);
        i += 1;
      } else {
        if (n1) chosen.push(n1);
      }
    }
  }
  if (!chosen.length) return null;
  return chosen[chosen.length - 1];
};

const extractInvoiceNumber = () => {
  const header =
    firstLineMatch(/(?:ELECTRONIC\s+INVOICE\s+EXPORT|FACTURA\s+DE\s+EXPORTACI[OÓ]N|COMMERCIAL\s+INVOICE|FACTURA\s+COMERCIAL)/i);
  if (header) {
    const nums = pickAllNumeric(header, 3);
    if (nums.length) return nums[nums.length - 1];
  }
  const label =
    firstLineMatch(/(?:Invoice\s*(?:Number|No\.?)|Factura\s*(?:N[o°º]\.?|N[uú]mero)?)/i);
  if (label) {
    const n = pickAllNumeric(label, 3);
    if (n.length) return n[n.length - 1];
  }
  const hm = raw.match(/(\d{3,})\s*[-–—]\s*(\d{3,})/);
  if (hm) return stripZeros(hm[2]);
  return null;
};

const extractExportInvoiceStrict = () => {
  const m = raw.match(/(?:FACTURA(?:\s+DE\s+EXPORTACI[oó]N)?|INVOICE)[^\n]{0,30}?(\d{4})\s*[-–—]\s*(\d{8})/i);
  return m ? `${m[1]}-${m[2]}` : null;
};

/* ===================== Helpers específicos MIC/CRT ===================== */

const coerceCrtForFilename = (s) => String(s || '').replace(/\//g, '-').trim();

const findFieldValue = (fieldNo, valueRe, opts = {}) => {
  const maxChars = opts.maxChars ?? 140;
  const re = new RegExp(
    String.raw`(?:^|\n)\s*(?:Campo\s*)?${fieldNo}\s*(?:[:\-]?\s*)?(?:[A-ZÁÉÍÓÚÑ/ ]{0,60}\s*)?(${valueRe.source})`,
    'i'
  );
  const m = raw.match(re);
  if (m && m[1]) return m[1].trim();

  const re2 = new RegExp(
    String.raw`\b(?:Campo\s*)?${fieldNo}\b[\s:.\-]{0,12}(.{0,${maxChars}})`,
    'i'
  );
  const m2 = raw.match(re2);
  if (m2 && m2[1]) {
    const mm = m2[1].match(valueRe);
    if (mm) return (mm[0] || '').trim();
  }
  return null;
};

// CRT campo 2 (mantener ceros a la izquierda): extrae el valor tal cual después de "2 Numero"
const extractCrtFromField2Numero = () => {
  const isBad = (v) => !v || /^(NUMERO|NÚMERO|NUMBER)$/i.test(String(v).trim());
  const hasDigit = (v) => /\d/.test(String(v || ''));

  // Caso típico multilinea: puede venir "2" + "Numero" + (repite "Numero") + valor
  let m = raw.match(
    /(?:^|\n)\s*2\s*(?:\r?\n)+\s*(?:Numero|N[uú]mero|Number)\b[^\n]*\r?\n\s*([A-Z0-9][A-Z0-9.\-\/]{2,40})(?:\r?\n\s*([A-Z0-9][A-Z0-9.\-\/]{4,40}))?/i
  );

  if (m && m[1]) {
    const c1 = m[1].trim();
    const c2 = (m[2] || '').trim();
    if (!isBad(c1) && hasDigit(c1)) return c1;
    if (c2 && !isBad(c2) && hasDigit(c2)) return c2;
  }

  // Inline: "2 Numero: XXXXX"
  m = raw.match(
    /(?:^|\n)\s*2\s*(?:Numero|N[uú]mero|Number)\b[^\n]*[:\-]?\s*([A-Z0-9][A-Z0-9.\-\/]{4,40})/i
  );
  if (m && m[1] && !isBad(m[1]) && hasDigit(m[1])) return m[1].trim();

  return null;
};

// Fallback CRT: por etiqueta "N° carta de porte"
const extractCrtFromCartaDePorte = () => {
  const m = raw.match(/N[°º\?]?\s*carta\s*de\s*porte[^\n]*\r?\n\s*([A-Z0-9][A-Z0-9.\-\/]{6,40})/i);
  return m ? m[1].trim() : null;
};

// MIC ID flexible desde el bloque del campo 4 (alfanumérico o numérico, sin formato fijo)
const extractMicIdFlexible = () => {
  // 1) Intento vía findFieldValue (si el valor aparece inline cerca de "4")
  // Acepta alfanumérico con . - /, mínimo 4 chars, debe contener al menos un dígito
  const reVal = /[A-Z0-9][A-Z0-9.\-\/]{3,60}/i;
  let v = findFieldValue(4, reVal);
  if (v) {
    v = String(v).trim();
    if (/\d/.test(v)) return v;
  }

  // 2) Layout típico del PDF: "4" en una línea, luego alguna etiqueta rara (ej "N¿"), y en la siguiente el valor
  let m = raw.match(/(?:^|\n)\s*4\s*(?:\r?\n)+[^\n]*\r?\n\s*([A-Z0-9][A-Z0-9.\-\/]{3,60})\b/i);
  if (m && m[1] && /\d/.test(m[1])) return m[1].trim();

  // 3) Otro layout: "4" y el valor en la línea siguiente directa
  m = raw.match(/(?:^|\n)\s*4\s*(?:\r?\n)+\s*([A-Z0-9][A-Z0-9.\-\/]{3,60})\b/i);
  if (m && m[1] && /\d/.test(m[1])) return m[1].trim();

  return null;
};

/* ===================== Regex MIC / CRT ===================== */

// MIC gate: el header debe tener MIC/DTA
const reMicHeaderStrict = /\bMIC\/DTA\b/i;

// MIC refuerzo: requerido
const reMicAduanaPartida = /(FIRMA\s+Y\s+SELLO\s+DE\s+ADUANA\s+DE\s+PARTIDA)/i;

// CRT refuerzos requeridos
const reCrtMontoReembolso = /(MONTO\s+DE\s+REEMBOLSO\s+CONTRA\s+ENTREGA)/i;
const reCrtMontoFleteExt  = /(MONTO\s+DEL\s+FLETE\s+EXTERNO)/i;

// Evitar confundir CRT con MIC cortado (si es alfanumérico, solo aplica el patrón típico)
const reMicIdCut = /\b\dAR\d{6}[A-Z]\b/i;

// ORDEN/ORDER
const reOrderGeneric = /\b(?:ORDEN|ORDER)\b[:\s\-\u2013\u2014]*([0-9]{6,12})/i;

/* ======= Señales generales (para factura / etc.) ======= */
const isCertOrigen = /(CERTIFICADO\s+DE\s+ORIGEN(?:\s+DIGITAL)?|CERTIFICATE\s+OF\s+ORIGIN)/i.test(norm);

const isBooking      = /(consolidated\s+booking\s+advice|booking\s+advice|booking\s+confirmation|booking\s+notice)/i.test(norm);
const isPacking      = /packing\s+list/i.test(norm);
const isConsolidated = /consolidated\s+packing\s+list/i.test(norm);
const isFactura      = !isCertOrigen && /(electronic\s+invoice\s+export|factura\s+de\s+exportaci[oó]n|commercial\s+invoice|factura\s+comercial)/i.test(norm);

/* ===================== Detección de tipo ===================== */

let tipo = 'otros';
let descartar  = false;
let incompleto = false;
let newFileName = null;

let micId = null;
let crtId = null;
let bothHeaders = false;
let isScan = false;

const hasText = !!(raw && raw.trim().length);

// ORDEN
let orderNumber = null;

/* ======= MIC/CRT/SCAN ======= */

if (!hasText) {
  tipo = 'scan';
  isScan = true;
} else {
  const isBookingText = isBooking;

  // MIC gate: MIC/DTA + Firma y sello de Aduana de Partida
  const micGate = reMicHeaderStrict.test(norm) && reMicAduanaPartida.test(norm);

  // CRT gate: tus dos frases predeterminadas
  const crtGate = !isBookingText && reCrtMontoReembolso.test(norm) && reCrtMontoFleteExt.test(norm);

  // IDs
  micId = micGate ? extractMicIdFlexible() : null;
  crtId = crtGate ? (extractCrtFromField2Numero() || extractCrtFromCartaDePorte()) : null;

  // Normalizaciones CRT
  if (crtId) {
    const c = crtId.replace(/\s+/g, '');
    if (reMicIdCut.test(c)) crtId = null;
  }
  if (crtId) crtId = coerceCrtForFilename(crtId);
  const crtIdNorm = crtId ? normalizeNamePart(crtId) : null;

  // ORDER genérico
  const mo = norm.match(reOrderGeneric);
  if (mo) orderNumber = stripZeros(mo[1]);

  // ORDER por ubicaciones fijas si no apareció
  // CRT: campo 11, MIC: campo 38
  if (!orderNumber && (crtGate || micGate)) {
    const f11 = findFieldValue(11, /\b0*([0-9]{6,12})\b/i);
    if (f11) {
      const m = f11.match(/\b0*([0-9]{6,12})\b/);
      if (m) orderNumber = stripZeros(m[1]);
    }
  }
  if (!orderNumber && (crtGate || micGate)) {
    const f38 = findFieldValue(38, /\b0*([0-9]{6,12})\b/i);
    if (f38) {
      const m = f38.match(/\b0*([0-9]{6,12})\b/);
      if (m) orderNumber = stripZeros(m[1]);
    }
  }

  // Compatibilidad extra
  if (!orderNumber) {
    const mFO = norm.match(/(?:FACTURA|INVOICE)[^\n]{0,60}?\b(?:ORDEN|ORDER)\b[^\d]{0,10}([0-9]{6,12})/i);
    if (mFO) orderNumber = stripZeros(mFO[1]);
  }

  // Headers finales
  const micHeader = !!micId && micGate;
  const crtHeader = !!crtIdNorm && crtGate;
  bothHeaders = micHeader && crtHeader;

  // Naming MIC/CRT (solo si hay IDs reales)
  if (bothHeaders) {
    tipo = 'crt';
    newFileName = orderNumber
      ? `${micId}_${orderNumber}_${crtIdNorm}_MIC_CT`
      : `${micId}_${crtIdNorm}_MIC_CT`;
    if (!orderNumber) incompleto = true;
  } else if (micHeader) {
    tipo = 'mic';
    newFileName = orderNumber
      ? `${micId}_${orderNumber}_MIC-DTA`
      : `${micId}_MIC-DTA`;
    if (!orderNumber) incompleto = true;
  } else if (crtHeader) {
    tipo = 'crt';
    newFileName = orderNumber
      ? `${orderNumber}_${crtIdNorm}_CT`
      : `${crtIdNorm}_CT`;
    if (!orderNumber) incompleto = true;
  }
}

/* ======= Lógica si no hubo MIC/CRT/SCAN ======= */

let shipmentList = [...raw.matchAll(/(?:^|\s)(?:Shipment\s*(?:Number)?|N[uú]mero\s+de\s+Env[ií]o|Numero\s+de\s+Envio)\s*[:#]?\s*0*([0-9]{6,})/gim)]
                   .map(m => stripZeros(m[1]));
shipmentList = [...new Set(shipmentList)].sort((a, b) => Number(b) - Number(a));
let shipmentNumber = shipmentList[0] || null;

/* ====== Detección de Permiso de Exportación (FIX: usar isFactura, no tipo) ====== */
let exportPermit = null;
let hasExportPermit = false;

if (isFactura) {
  const permitRegexes = [
    /(Permiso\s+de\s+Exportaci[oó]n|Permiso\s+de\s+Embarque|Export\s+Permit|Shipping\s+Permit)\s*[:#\-]?\s*([A-Z0-9.\-\/\s]{6,30})/i,
    /\bP\.?\s*E\.?\s*[:#\-]?\s*([A-Z0-9.\-\/]{6,30})\b/i
  ];

  for (const rx of permitRegexes) {
    const m = raw.match(rx);
    if (m && m[2]) {
      exportPermit = m[2].trim().replace(/\s+/g, ' ');
      hasExportPermit = true;
      break;
    }
    if (m && m[1] && !m[2]) {
      exportPermit = m[1].trim().replace(/\s+/g, ' ');
      hasExportPermit = true;
      break;
    }
  }
}

let shippingPoint = null;
let shippingPointNormalized = null;

let mSP = raw.match(/(?:SHIPPING\s+POINT|Punto\s+de\s+Embarque)\s*[:#\-]?\s*([A-Za-z0-9 .\-_/]{2,60})/i);
if (mSP && mSP[1]) {
  shippingPoint = mSP[1].trim();
}
if (!shippingPoint) {
  const lines = raw.split(/\r?\n/);
  for (let i = 0; i < lines.length; i++) {
    if (/(?:SHIPPING\s+POINT|Punto\s+de\s+Embarque)\s*[:#!\-]*\s*$/i.test(lines[i])) {
      const cand = (lines[i+1] || '').trim();
      if (cand) {
        shippingPoint = cand.replace(/^[\s\-:.#/]+|[\s\-:.#/]+$/g,'');
        break;
      }
    }
  }
}
if (shippingPoint) {
  shippingPoint = shippingPoint.replace(/\s{2,}/g,' ').replace(/[|]+/g,'').trim();
  shippingPointNormalized = shippingPoint.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toUpperCase();
}

if (!newFileName && !['mic','crt','scan'].includes(tipo)) {

  // BOOKING ADVICE: SOLO ZCB1/ZCB3 (si no es ninguno -> otros)
  if (isBooking) {
    if (subjectCode === 'ZCB1') tipo = 'booking_advice_zcb1';
    else if (subjectCode === 'ZCB3') tipo = 'booking_advice_zcb3';
    else tipo = 'otros';
  } else if (isPacking) {
    let transportMode = (raw.match(/(?:Transport\s*Mode|Modo\s+de\s+Transporte)\s*[:\s]*([A-Za-z]+)/i)?.[1] || '').toUpperCase();
    if (isConsolidated) {
      tipo = 'packing_maritimo';
    } else if (transportMode === 'FCL' || transportMode === 'LCL') {
      tipo = 'packing_maritimo_sin_consolidar';
      descartar = true;
    } else if (['TL', 'FTL', 'LTL', 'CAMION'].includes(transportMode)) {
      tipo = 'packing_terrestre';
    } else {
      const maritimeHints = /(vessel|port\s+of\s+(loading|discharge)|container|fcl|lcl|bill\s+of\s+lading|\bbl\b)/i.test(norm);
      tipo = maritimeHints ? 'packing_maritimo' : 'packing_terrestre';
    }
  } else if (isFactura) {
    tipo = 'factura';
  } else {
    tipo = 'otros';
  }

  // FACTURA
  let invoiceNumber = null;
  if (tipo === 'factura') {
    invoiceNumber = extractInvoiceNumber();
    orderNumber = extractOrderFromInternalDoc(raw) || orderNumber;
    if (!orderNumber) {
      const lineON = raw.match(/^.*Order\s*Number.*$/im);
      if (lineON) {
        const m = lineON[0].match(/\b0*([0-9]{6,})\b/);
        if (m) orderNumber = stripZeros(m[1]);
      }
    }
    if (invoiceNumber && orderNumber) {
      newFileName = `${invoiceNumber}_${orderNumber}_FC`;
    } else {
      incompleto = true;
    }
  }

  // BOOKING ADVICE (ZCB1/ZCB3)
  if (
    !newFileName &&
    (tipo === 'booking_advice_zcb1' || tipo === 'booking_advice_zcb3')
  ) {
    if (!orderNumber) {
      const lineON = raw.match(/^.*Order\s*Number.*$/im);
      if (lineON) {
        const m = lineON[0].match(/\b0*([0-9]{6,})\b/);
        if (m) orderNumber = stripZeros(m[1]);
      }
    }
    if (shipmentNumber && orderNumber) {
      newFileName = subjectCode
        ? `${shipmentNumber}_${orderNumber}_${subjectCode}_BA`
        : `${shipmentNumber}_${orderNumber}_BA`;
    } else {
      incompleto = true;
    }
  }

  // PACKING LIST
  if (!newFileName && (tipo === 'packing_maritimo' || tipo === 'packing_terrestre' || tipo === 'packing_maritimo_sin_consolidar')) {
    if (!orderNumber) {
      const lineON = raw.match(/^.*Order\s*Number.*$/im);
      if (lineON) {
        const m = lineON[0].match(/\b0*([0-9]{6,})\b/);
        if (m) orderNumber = stripZeros(m[1]);
      }
    }
    if (shipmentNumber && orderNumber) {
      newFileName = `${shipmentNumber}_${orderNumber}_PL`;
    } else {
      incompleto = true;
    }
  }
}

/* ===================== Fallbacks y normalización final ===================== */

if (!orderNumber) {
  const mo2 = raw.normalize('NFD').replace(/[\u0300-\u036f]/g, '')
               .match(/\b(?:ORDEN|ORDER)\b[:\s\-\u2013\u2014]*([0-9]{6,12})/i);
  if (mo2) orderNumber = stripZeros(mo2[1]);
}

const originalName = pick($json.fileName, $binary?.data?.fileName, 'adjunto.pdf');
const ext = (originalName.match(/\.[A-Za-z0-9]+$/)?.[0]) || '.pdf';
const baseOriginal = originalName.replace(/\.[A-Za-z0-9]+$/, '');

if (!newFileName) {
  if (tipo === 'scan') {
    newFileName = `${baseOriginal}_SCAN`;
  } else {
    newFileName = normalizeNamePart(baseOriginal);
  }
}
newFileName = normalizeNamePart(newFileName) + (newFileName.toLowerCase().endsWith(ext.toLowerCase()) ? '' : ext);

// Fijación final de orderNumber desde el nombre
if (!orderNumber && newFileName) {
  const fname = String(newFileName);
  let m = fname.match(/_([0-9]{6,12})_/);
  if (m) {
    orderNumber = stripZeros(m[1]);
  } else {
    const base = fname.replace(/\.[A-Za-z0-9]+$/,'');
    const parts = base.split('_');
    const cand = parts.find(p => /^\d{6,12}$/.test(p));
    if (cand) orderNumber = stripZeros(cand);
  }
}

/* ===================== Salida (mantener binary) ===================== */
return {
  json: {
    tipo,
    descartar,
    incompleto,
    shipmentNumber,
    shipmentList,
    orderNumber,
    invoiceNumber: undefined,
    micId,
    crtId,
    bothHeaders,
    isScan,
    newFileName,
    originalName,

    hasExportPermit,
    exportPermit,
    exportPermitNumber: exportPermit || null,
    shippingPoint: shippingPoint || null,
    shippingPointNormalized: shippingPointNormalized || null,

    emailSubject: emailSubject || null,
    subjectCode: subjectCode || null
  },
  binary: $binary
};

const out = []

const removeDiacritics = (s) =>
  String(s || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '')

const normalizeSubject = (s) =>
  removeDiacritics(s).replace(/\s+/g, ' ').trim()

const stripReplyFwPrefixes = (s) => {
  let x = String(s || '').trim()
  while (/^(?:RE|RV|FW|FWD)\s*:/i.test(x)) {
    x = x.replace(/^(?:RE|RV|FW|FWD)\s*:\s*/i, '').trim()
  }
  return x
}

const extractDate = (subjectClean) => {
  const m = subjectClean.match(/\b(\d{2})[\/\-](\d{2})[\/\-](\d{4})\b/)
  return m ? `${m[1]}/${m[2]}/${m[3]}` : null
}

// ZCB1/ZCB3: "Document 47682105"
const extractShipmentFromZcb = (subjectClean) => {
  const m = subjectClean.match(/\bDOCUMENT\b\s*0*([0-9]{6,})\b/i)
  return m ? m[1] : null
}

// DOCUMENT: debe ser primera palabra
const isDocumentFirstWord = (subjectClean) => /^\s*DOCUMENT\b/i.test(subjectClean)

// CERT ANALYSIS: "Shp No -0047687667"
const extractShipmentFromCertAnalysis = (subjectClean) => {
  const m = subjectClean.match(/\bSHP\s*NO\b\s*[-: ]\s*0*([0-9]{6,})\b/i)
  return m ? m[1] : null
}

// ISO -> "YYYY-MM-DD HH:mm" en Argentina
const formatLocalAr = (iso) => {
  if (!iso) return null
  const d = new Date(iso)
  if (isNaN(d.getTime())) return null

  const parts = new Intl.DateTimeFormat('sv-SE', {
    timeZone: 'America/Argentina/Buenos_Aires',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
  })
    .formatToParts(d)
    .reduce((acc, p) => {
      acc[p.type] = p.value
      return acc
    }, {})

  return `${parts.year}-${parts.month}-${parts.day} ${parts.hour}:${parts.minute}`
}

for (const item of $input.all()) {
  const emailSubjectRaw = item.json?.subject ?? item.json?.headers?.subject ?? ''
  const emailSubjectNormalized = normalizeSubject(emailSubjectRaw)
  const subjectClean = stripReplyFwPrefixes(emailSubjectNormalized)

  const dateSent = extractDate(subjectClean)

  let subjectCode = null
  let sapDeliveryNumber = null
  let shipmentNumberFromSubject = null

  // SOLO estos códigos (sin fallback)
  const mZcb = subjectClean.match(/\b(ZCB1|ZCB3)\b/i)
  if (mZcb) {
    subjectCode = mZcb[1].toUpperCase()
    shipmentNumberFromSubject = extractShipmentFromZcb(subjectClean)
  } else if (/\bCERT\s*ANALYSIS\b/i.test(subjectClean)) {
    subjectCode = 'CERT_ANALYSIS'
    shipmentNumberFromSubject = extractShipmentFromCertAnalysis(subjectClean)
  } else if (isDocumentFirstWord(subjectClean)) {
    subjectCode = 'DOCUMENT'
    const m = subjectClean.match(/^\s*DOCUMENT\b\s*0*([0-9]{6,})\b/i)
    sapDeliveryNumber = m ? m[1] : null
  }

  const receivedAtLocalAr = formatLocalAr(item.json?.date)

  for (const binary of Object.values(item.binary || {})) {
    if (!binary) continue
    const name = (binary.fileName || '').toLowerCase()
    const mime = (binary.mimeType || '').toLowerCase()

    if (mime === 'application/pdf' || name.endsWith('.pdf')) {
      const json = {
        fileName: binary.fileName || 'adjunto.pdf',
        emailSubject: emailSubjectRaw,
        emailSubjectNormalized,
      }

      if (receivedAtLocalAr) json.receivedAtLocalAr = receivedAtLocalAr

      // agregar solo si existe
      if (subjectCode) json.subjectCode = subjectCode
      if (dateSent) json.dateSent = dateSent

      // solo para DOCUMENT
      if (subjectCode === 'DOCUMENT' && sapDeliveryNumber) {
        json.sapDeliveryNumber = sapDeliveryNumber
      }

      // solo para ZCB1/ZCB3/CERT_ANALYSIS
      if (
        (subjectCode === 'ZCB1' || subjectCode === 'ZCB3' || subjectCode === 'CERT_ANALYSIS') &&
        shipmentNumberFromSubject
      ) {
        json.shipmentNumberFromSubject = shipmentNumberFromSubject
      }

      out.push({
        json,
        binary: { data: binary }
      })
    }
  }
}

return out.length ? out : []

