/**
 * Nodo: "Clasificar Documento y renombrar pdf"
 * Tarea...detectar Permiso de Exportación en FACTURAS y extraer Shipping
 */

const raw  = ($json.text || '');
const norm = raw.normalize('NFD').replace(/[\u0300-\u036f]/g, '');

/* ======= Asunto del email (viene de la rama "Seleccionar PDF") ======= */
const sel = $items('Seleccionar PDF')?.[$itemIndex]?.json || {};
const emailSubject = sel.emailSubject ?? sel.subject ?? sel.headers?.subject ?? null;
let subjectCode = sel.subjectCode ?? (emailSubject ? String(emailSubject).trim().slice(0, 4) : null);
subjectCode = subjectCode ? String(subjectCode).trim().slice(0, 4).toUpperCase() : null;

const stripZeros = (s) => {
  const x = String(s || '').replace(/^0+/, '');
  return x === '' ? '0' : x;
};
const pick = (...vals) => vals.find(v => v != null && v !== '') ?? null;

const normalizeNamePart = (s) => String(s || '')
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^\w.\-]+/g, '_')
  .replace(/_{2,}/g, '_')
  .replace(/^_+|_+$/g, '')
  .toUpperCase();

const pickAllNumeric = (s, minLen = 6) => {
  if (!s) return [];
  return [...s.matchAll(new RegExp(String.raw`\b0*([0-9]{${minLen},})\b`, 'g'))]
         .map(m => stripZeros(m[1]));
};

const firstLineMatch = (re) => {
  const m = raw.match(new RegExp(`^.*${re.source}.*$`, 'im'));
  return m ? m[0] : null;
};

const extractOrderFromInternalDoc = (text) => {
  const lines = text.split(/\r?\n/);
  const chosen = [];
  const label = /(?:Internal\s+Document\s+Number|Internal\s+Order\s+Number|N[úu]mero\s+de\s+Orden\s+Intern[ao])/i;
  const firstLongNum = (s) => {
    const arr = pickAllNumeric(s, 6);
    return arr.length ? arr[0] : null;
  };
  for (let i = 0; i < lines.length; i++) {
    const m1 = lines[i].match(new RegExp(label.source + String.raw`\s*[:#-]?\s*([^\n]*)`, 'i'));
    if (m1) {
      let n1 = firstLongNum(m1[1]);
      if (!n1 && lines[i + 1] && !new RegExp(label.source, 'i').test(lines[i + 1])) {
        n1 = firstLongNum(lines[i + 1]);
      }
      const next = lines[i + 1];
      const m2 = next ? next.match(new RegExp(label.source + String.raw`\s*[:#-]?\s*([^\n]*)`, 'i')) : null;
      if (m2) {
        let n2 = firstLongNum(m2[1]);
        if (!n2 && lines[i + 2] && !new RegExp(label.source, 'i').test(lines[i + 2])) {
          n2 = firstLongNum(lines[i + 2]);
        }
        if (n2) chosen.push(n2);
        else if (n1) chosen.push(n1);
        i += 1;
      } else {
        if (n1) chosen.push(n1);
      }
    }
  }
  if (!chosen.length) return null;
  return chosen[chosen.length - 1];
};

const extractInvoiceNumber = () => {
  const header =
    firstLineMatch(/(?:ELECTRONIC\s+INVOICE\s+EXPORT|FACTURA\s+DE\s+EXPORTACI[OÓ]N|COMMERCIAL\s+INVOICE|FACTURA\s+COMERCIAL)/i);
  if (header) {
    const nums = pickAllNumeric(header, 3);
    if (nums.length) return nums[nums.length - 1];
  }
  const label =
    firstLineMatch(/(?:Invoice\s*(?:Number|No\.?)|Factura\s*(?:N[o°º]\.?|N[uú]mero)?)/i);
  if (label) {
    const n = pickAllNumeric(label, 3);
    if (n.length) return n[n.length - 1];
  }
  const hm = raw.match(/(\d{3,})\s*[-–—]\s*(\d{3,})/);
  if (hm) return stripZeros(hm[2]);
  return null;
};

const extractExportInvoiceStrict = () => {
  const m = raw.match(/(?:FACTURA(?:\s+DE\s+EXPORTACI[oó]N)?|INVOICE)[^\n]{0,30}?(\d{4})\s*[-–—]\s*(\d{8})/i);
  return m ? `${m[1]}-${m[2]}` : null;
};

// Regex MIC / CRT
const reMicHeader = /(MANIFIESTO\s+INTERNACIONAL\s+DE\s+CARGA|INTERNATIONAL\s+CARGO\s+MANIFEST|MIC\/DTA|MIC\s*DTA)/i;
const reCrtHeader = /(CONTRATO\s+DE\s+TRANSPORTE|CONSIGNMENT\s+NOTE|CRT\b)/i;
const reMicId     = /\b\d{2}\s*ARG\s*\d{6,}\b/i;

// CRT ID: soportar variantes
const reCrtList = [
  /\b\d{5,}[A-Z]{2}\d{2}\b/i,
  /\b\d{3}AR(?:G)?[A-Z]*[.\-]?\d+\/\d{2,4}\b/i,
  /\bAR\d+\/\d{2,4}\b/i,
  /\b\d{3}AR(?:G)?[A-Z]*[.\-]?\d+\-\d{2,4}\b/i,
  /\bAR\d+\-\d{2,4}\b/i
];

// Regex ORDEN/ORDER
const reOrderGeneric = /\b(?:ORDEN|ORDER)\b[:\s\-\u2013\u2014]*([0-9]{6,12})/i;

/* ===================== Detección de tipo ===================== */

let tipo = 'otros';
let descartar  = false;
let incompleto = false;
let newFileName = null;

let micId = null;
let crtId = null;
let bothHeaders = false;
let isScan = false;

const hasText = !!(raw && raw.trim().length);

// ORDEN accesible
let orderNumber = null;

/* ======= MIC/CRT/SCAN ======= */

if (!hasText) {
  tipo = 'scan';
  isScan = true;
} else {
  const micHeader = reMicHeader.test(norm);
  const crtHeader = reCrtHeader.test(norm);
  bothHeaders = micHeader && crtHeader;

  micId = (norm.match(reMicId) || [])[0] || null;

  for (const rx of reCrtList) {
    const m = norm.match(rx);
    if (m) { crtId = m[0]; break; }
  }
  if (!crtId) {
    const fnameU = normalizeNamePart(pick($json.fileName, $binary?.data?.fileName, '') || '');
    for (const rx of reCrtList) {
      const m = fnameU.match(rx);
      if (m) { crtId = m[0]; break; }
    }
  }
  const crtIdNorm = crtId ? normalizeNamePart(crtId) : null;

  let orderFromOrden = null;
  const mo = norm.match(reOrderGeneric);
  if (mo) {
    orderFromOrden = stripZeros(mo[1]);
    orderNumber = orderFromOrden;
  }

  if (!orderNumber) {
    const mFO = norm.match(/(?:FACTURA|INVOICE)[^\n]{0,60}?\b(?:ORDEN|ORDER)\b[^\d]{0,10}([0-9]{6,12})/i);
    if (mFO) orderNumber = stripZeros(mFO[1]);
  }

  const invoiceStrict = extractExportInvoiceStrict();

  if (bothHeaders) {
    tipo = 'crt';
    if (micId && orderFromOrden) {
      newFileName = crtIdNorm
        ? `${micId}_${orderFromOrden}_${crtIdNorm}_MIC_CT`
        : `${micId}_${orderFromOrden}_MIC_CT`;
    } else if (micId && invoiceStrict) {
      newFileName = crtIdNorm
        ? `${micId}_${invoiceStrict}_${crtIdNorm}_MIC_CT`
        : `${micId}_${invoiceStrict}_MIC_CT`;
    } else if (micId && crtIdNorm) {
      newFileName = `${micId}_${crtIdNorm}_MIC_CT`;
    } else if (micId) {
      newFileName = `${micId}_MIC_CT`;
    } else if (crtIdNorm) {
      newFileName = `${crtIdNorm}_MIC_CT`;
    }
  } else if (micHeader) {
    tipo = 'mic';
    if (micId && orderFromOrden) {
      newFileName = `${micId}_${orderFromOrden}_MIC-DTA`;
    } else if (micId) {
      newFileName = `${micId}_MIC-DTA`;
    }
  } else if (crtHeader || crtId) {
    tipo = 'crt';
    if (crtIdNorm) {
      newFileName = `${crtIdNorm}_CT`;
    }
  }
}

/* ======= Lógica si no hubo MIC/CRT/SCAN ======= */

const isCertOrigen = /(CERTIFICADO\s+DE\s+ORIGEN(?:\s+DIGITAL)?|CERTIFICATE\s+OF\s+ORIGIN)/i.test(norm);

const isBooking      = /(consolidated\s+booking\s+advice|booking\s+advice|booking\s+confirmation|booking\s+notice)/i.test(norm);
const isPacking      = /packing\s+list/i.test(norm);
const isConsolidated = /consolidated\s+packing\s+list/i.test(norm);
const isFactura      = !isCertOrigen && /(electronic\s+invoice\s+export|factura\s+de\s+exportaci[oó]n|commercial\s+invoice|factura\s+comercial)/i.test(norm);

let shipmentList = [...raw.matchAll(/(?:^|\s)(?:Shipment\s*(?:Number)?|N[uú]mero\s+de\s+Env[ií]o|Numero\s+de\s+Envio)\s*[:#]?\s*0*([0-9]{6,})/gim)]
                   .map(m => stripZeros(m[1]));
shipmentList = [...new Set(shipmentList)].sort((a, b) => Number(b) - Number(a));
let shipmentNumber = shipmentList[0] || null;

/* ====== Detección de Permiso de Exportación (para facturas) ====== */
let exportPermit = null;
let hasExportPermit = false;

const permitRegexes = [
  /(Permiso\s+de\s+Exportaci[oó]n|Permiso\s+de\s+Embarque|Export\s+Permit|Shipping\s+Permit)\s*[:#\-]?\s*([A-Z0-9.\-\/\s]{6,30})/i,
  /\bP\.?\s*E\.?\s*[:#\-]?\s*([A-Z0-9.\-\/]{6,30})\b/i
];

for (const rx of permitRegexes) {
  const m = raw.match(rx);
  if (m && m[2]) {
    exportPermit = m[2].trim().replace(/\s+/g, ' ');
    hasExportPermit = true;
    break;
  }
  if (m && m[1] && !m[2]) {
    exportPermit = m[1].trim().replace(/\s+/g, ' ');
    hasExportPermit = true;
    break;
  }
}

let shippingPoint = null;
let shippingPointNormalized = null;

let mSP = raw.match(/(?:SHIPPING\s+POINT|Punto\s+de\s+Embarque)\s*[:#\-]?\s*([A-Za-z0-9 .\-_/]{2,60})/i);
if (mSP && mSP[1]) {
  shippingPoint = mSP[1].trim();
}
if (!shippingPoint) {
  const lines = raw.split(/\r?\n/);
  for (let i = 0; i < lines.length; i++) {
    if (/(?:SHIPPING\s+POINT|Punto\s+de\s+Embarque)\s*[:#!\-]*\s*$/i.test(lines[i])) {
      const cand = (lines[i+1] || '').trim();
      if (cand) {
        shippingPoint = cand.replace(/^[\s\-:.#/]+|[\s\-:.#/]+$/g,'');
        break;
      }
    }
  }
}
if (shippingPoint) {
  shippingPoint = shippingPoint.replace(/\s{2,}/g,' ').replace(/[|]+/g,'').trim();
  shippingPointNormalized = shippingPoint.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toUpperCase();
}

if (!newFileName && !['mic','crt','scan'].includes(tipo)) {

  if (isBooking) {
    tipo = 'booking_advice';
  } else if (isPacking) {
    let transportMode = (raw.match(/(?:Transport\s*Mode|Modo\s+de\s+Transporte)\s*[:\s]*([A-Za-z]+)/i)?.[1] || '').toUpperCase();
    if (isConsolidated) {
      tipo = 'packing_maritimo';
    } else if (transportMode === 'FCL' || transportMode === 'LCL') {
      tipo = 'packing_maritimo_sin_consolidar';
      descartar = true;
    } else if (['TL', 'FTL', 'LTL', 'CAMION'].includes(transportMode)) {
      tipo = 'packing_terrestre';
    } else {
      const maritimeHints = /(vessel|port\s+of\s+(loading|discharge)|container|fcl|lcl|bill\s+of\s+lading|\bbl\b)/i.test(norm);
      tipo = maritimeHints ? 'packing_maritimo' : 'packing_terrestre';
    }
  } else if (isFactura) {
    tipo = 'factura';
  } else {
    tipo = 'otros';
  }

  // FACTURA
  let invoiceNumber = null;
  if (tipo === 'factura') {
    invoiceNumber = extractInvoiceNumber();
    orderNumber = extractOrderFromInternalDoc(raw) || orderNumber;
    if (!orderNumber) {
      const lineON = raw.match(/^.*Order\s*Number.*$/im);
      if (lineON) {
        const m = lineON[0].match(/\b0*([0-9]{6,})\b/);
        if (m) orderNumber = stripZeros(m[1]);
      }
    }
    if (invoiceNumber && orderNumber) {
      newFileName = `${invoiceNumber}_${orderNumber}_FC`;
    } else {
      incompleto = true;
    }
  }

  // BOOKING ADVICE
  if (!newFileName && tipo === 'booking_advice') {
    if (!orderNumber) {
      const lineON = raw.match(/^.*Order\s*Number.*$/im);
      if (lineON) {
        const m = lineON[0].match(/\b0*([0-9]{6,})\b/);
        if (m) orderNumber = stripZeros(m[1]);
      }
    }
    if (shipmentNumber && orderNumber) {
      newFileName = subjectCode ? `${shipmentNumber}_${orderNumber}_${subjectCode}_BA` : `${shipmentNumber}_${orderNumber}_BA`;
    } else {
      incompleto = true;
    }
  }

  // PACKING LIST
  if (!newFileName && (tipo === 'packing_maritimo' || tipo === 'packing_terrestre' || tipo === 'packing_maritimo_sin_consolidar')) {
    if (!orderNumber) {
      const lineON = raw.match(/^.*Order\s*Number.*$/im);
      if (lineON) {
        const m = lineON[0].match(/\b0*([0-9]{6,})\b/);
        if (m) orderNumber = stripZeros(m[1]);
      }
    }
    if (shipmentNumber && orderNumber) {
      newFileName = `${shipmentNumber}_${orderNumber}_PL`;
    } else {
      incompleto = true;
    }
  }
}

/* ===================== Fallbacks y normalización final ===================== */

if (!orderNumber) {
  const mo2 = raw.normalize('NFD').replace(/[\u0300-\u036f]/g, '')
               .match(/\b(?:ORDEN|ORDER)\b[:\s\-\u2013\u2014]*([0-9]{6,12})/i);
  if (mo2) orderNumber = stripZeros(mo2[1]);
}

const originalName = pick($json.fileName, $binary?.data?.fileName, 'adjunto.pdf');
const ext = (originalName.match(/\.[A-Za-z0-9]+$/)?.[0]) || '.pdf';
const baseOriginal = originalName.replace(/\.[A-Za-z0-9]+$/, '');

if (!newFileName) {
  if (tipo === 'scan') {
    newFileName = `${baseOriginal}_SCAN`;
  } else {
    newFileName = normalizeNamePart(baseOriginal);
  }
}
newFileName = normalizeNamePart(newFileName) + (newFileName.toLowerCase().endsWith(ext.toLowerCase()) ? '' : ext);

// Fijación final de orderNumber desde el nombre
if (!orderNumber && newFileName) {
  const fname = String(newFileName);
  let m = fname.match(/_([0-9]{6,12})_/);
  if (m) {
    orderNumber = stripZeros(m[1]);
  } else {
    const base = fname.replace(/\.[A-Za-z0-9]+$/,'');
    const parts = base.split('_');
    const cand = parts.find(p => /^\d{6,12}$/.test(p));
    if (cand) orderNumber = stripZeros(cand);
  }
}

/* ===================== Salida ===================== */
return {
  json: {
    tipo,
    descartar,
    incompleto,
    shipmentNumber,
    shipmentList,
    orderNumber,
    invoiceNumber: undefined,   // compatibilidad histórica
    micId,
    crtId,
    bothHeaders,
    isScan,
    newFileName,
    originalName,

    // NUEVO:
    hasExportPermit,
    exportPermit,
    exportPermitNumber: exportPermit || null,
    shippingPoint: shippingPoint || null,
    shippingPointNormalized: shippingPointNormalized || null,

    // Email
    emailSubject: emailSubject || null,
    subjectCode: subjectCode || null
  }
};

