parameters.jsCode:
/**
 * Nodo: "CRT: armar nombre"
 * Regla base: <shipment>_<order>_CRT
 * Fallbacks si faltan datos y bandera incompleto:true
 */
const rawAI = $json || {};

const stripZeros = (s) => {
  const x = String(s || '').replace(/^0+/, '');
  return x === '' ? '0' : x;
};
const onlyDigits = (s) => (s ? String(s).replace(/\D+/g, '') : null);

let orderNumber    = onlyDigits(rawAI.order_number);
let shipmentNumber = onlyDigits(rawAI.shipment_number);
let documentNumber = onlyDigits(rawAI.document_number);
let vehiclePlate   = (rawAI.vehicle_plate || '').toUpperCase().replace(/\s+/g, '');
let issueDate      = rawAI.issue_date || null;

if (orderNumber)    orderNumber    = stripZeros(orderNumber);
if (shipmentNumber) shipmentNumber = stripZeros(shipmentNumber);
if (documentNumber) documentNumber = stripZeros(documentNumber);

let newFileName = null;
let incompleto  = false;

if (shipmentNumber && orderNumber) {
  newFileName = `${shipmentNumber}_${orderNumber}_CRT`;
} else {
  incompleto = true;
  if (shipmentNumber && documentNumber) {
    newFileName = `${shipmentNumber}_${documentNumber}_CRT`;
  } else if (orderNumber && documentNumber) {
    newFileName = `${documentNumber}_${orderNumber}_CRT`;
  } else if (shipmentNumber && vehiclePlate) {
    newFileName = `${shipmentNumber}_${vehiclePlate}_CRT`;
  } else if (documentNumber) {
    newFileName = `${documentNumber}_CRT`;
  } else {
    const ts = new Date().toISOString().slice(0,10).replace(/-/g,'');
    newFileName = `CRT_${ts}`;
  }
}

return {
  json: {
    tipo: 'mic_crt',
    incompleto,
    shipmentNumber,
    orderNumber,
    documentNumber,
    vehiclePlate,
    issueDate,
    newFileName
  }
};

// Lee el PDF binario y construye un data URL válido para OCR.space
const BIN = 'data'; // ← cámbialo si tu binario se llama distinto (p.ej. 'attachment_0')

// Lee el buffer real del PDF
const buf = await this.helpers.getBinaryDataBuffer(0, BIN);
const base64 = buf.toString('base64');

// Devolvemos solo el JSON con el data URL; el binario sigue viajando por la otra rama al Merge
return {
  json: {
    base64Image: 'data:application/pdf;base64,' + base64
  }
};

const out = [];

for (const item of $input.all()) {
  for (const [key, binary] of Object.entries(item.binary || {})) {
    if (!binary) continue;
    const name = (binary.fileName || '').toLowerCase();
    const mime = (binary.mimeType || '').toLowerCase();

    if (mime === 'application/pdf' || name.endsWith('.pdf')) {
      out.push({
        json: { fileName: binary.fileName || 'adjunto.pdf' },
        binary: { data: binary } // siempre "data"
      });
    }
  }
}

return out.length ? out : [];
